#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum KindEnum {
    LetKw,
    ConstKw,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for KindEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let kind_id: u16 = u16::from_napi_value(env, napi_val)?;
        match kind_id {
            15 => Ok(Self::LetKw), // "let"
            16 => Ok(Self::ConstKw), // "const"
            other => Err(::napi::Error::from_reason(format!(
                "unknown kind id {{other}} for KindEnum",
            ))),
        }
    }
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::ToNapiValue for KindEnum {
    unsafe fn to_napi_value(
        _env: ::napi::sys::napi_env,
        _val: Self,
    ) -> ::napi::Result<::napi::sys::napi_value> {
        Err(::napi::Error::from_reason("KindEnum is receive-only"))
    }
}

impl ::std::fmt::Display for KindEnum {
    fn fmt(&self, f: &mut ::std::fmt::Formatter<'_>) -> ::std::fmt::Result {
        f.write_str(match self {
            Self::LetKw => "let",
            Self::ConstKw => "const",
        })
    }
}

impl RenderableTransport for KindEnum {
    fn render_into(
        &self,
        dest: &mut dyn ::std::fmt::Write,
    ) -> Result<(), ::askama::Error> {
        dest.write_str(match self {
            Self::LetKw => "let",
            Self::ConstKw => "const",
        }).map_err(::askama::Error::from)
    }
}

