#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum UnaryExpressionOperatorEnum {
    Bang,
    Tilde,
    Minus,
    Plus,
    TypeofKw,
    VoidKw,
    DeleteKw,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for UnaryExpressionOperatorEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let kind_id: u16 = u16::from_napi_value(env, napi_val)?;
        match kind_id {
            17 => Ok(Self::Bang), // "!"
            91 => Ok(Self::Tilde), // "~"
            77 => Ok(Self::Minus), // "-"
            76 => Ok(Self::Plus), // "+"
            9 => Ok(Self::TypeofKw), // "typeof"
            92 => Ok(Self::VoidKw), // "void"
            93 => Ok(Self::DeleteKw), // "delete"
            other => Err(::napi::Error::from_reason(format!(
                "unknown kind id {{other}} for UnaryExpressionOperatorEnum",
            ))),
        }
    }
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::ToNapiValue for UnaryExpressionOperatorEnum {
    unsafe fn to_napi_value(
        _env: ::napi::sys::napi_env,
        _val: Self,
    ) -> ::napi::Result<::napi::sys::napi_value> {
        Err(::napi::Error::from_reason("UnaryExpressionOperatorEnum is receive-only"))
    }
}

impl ::std::fmt::Display for UnaryExpressionOperatorEnum {
    fn fmt(&self, f: &mut ::std::fmt::Formatter<'_>) -> ::std::fmt::Result {
        f.write_str(match self {
            Self::Bang => "!",
            Self::Tilde => "~",
            Self::Minus => "-",
            Self::Plus => "+",
            Self::TypeofKw => "typeof",
            Self::VoidKw => "void",
            Self::DeleteKw => "delete",
        })
    }
}

impl RenderableTransport for UnaryExpressionOperatorEnum {
    fn render_into(
        &self,
        dest: &mut dyn ::std::fmt::Write,
    ) -> Result<(), ::askama::Error> {
        dest.write_str(match self {
            Self::Bang => "!",
            Self::Tilde => "~",
            Self::Minus => "-",
            Self::Plus => "+",
            Self::TypeofKw => "typeof",
            Self::VoidKw => "void",
            Self::DeleteKw => "delete",
        }).map_err(::askama::Error::from)
    }
}

